#!/usr/bin/env node
/**
 * Builds ANALYTICS.pdf from ANALYTICS.md.
 *
 * Run locally:     npm run docs:analytics
 * Run in CI:       see .github/workflows/build-analytics-pdf.yml
 *                  (regenerates the PDF whenever ANALYTICS.md or
 *                   src/lib/analytics.js change, and commits the
 *                   PDF back to main with [skip ci]).
 *
 * The PDF is rendered to match the classic theme's Apple-inspired
 * typography (system fonts, single Action Blue accent, hairline tables).
 * A small "auto-generated" banner is injected at the top with the build
 * timestamp + commit SHA so a reader can verify it's current.
 */

import { mdToPdf } from 'md-to-pdf';
import { readFileSync } from 'node:fs';
import { execSync } from 'node:child_process';
import { fileURLToPath } from 'node:url';
import { dirname, resolve } from 'node:path';

const here = dirname(fileURLToPath(import.meta.url));
const repoRoot = resolve(here, '..');

const md = readFileSync(resolve(repoRoot, 'ANALYTICS.md'), 'utf8');

function safe(cmd, fallback = '') {
  try { return execSync(cmd, { cwd: repoRoot }).toString().trim(); }
  catch { return fallback; }
}

const sha = safe('git rev-parse --short HEAD', 'unknown');
const branch = safe('git rev-parse --abbrev-ref HEAD', 'unknown');
const builtAt = new Date().toISOString().replace('T', ' ').slice(0, 16) + ' UTC';

const banner = `> **Auto-generated PDF** — built from \`ANALYTICS.md\` (the editable source of truth) and \`src/lib/analytics.js\` (the runtime). Regenerated by CI on every change to either file.
>
> Built ${builtAt} · branch \`${branch}\` · commit \`${sha}\`

---

`;

const content = banner + md;

await mdToPdf(
  { content },
  {
    dest: resolve(repoRoot, 'ANALYTICS.pdf'),
    pdf_options: {
      format: 'A4',
      margin: { top: '22mm', right: '20mm', bottom: '22mm', left: '20mm' },
      printBackground: true,
      displayHeaderFooter: true,
      headerTemplate: `
        <div style="font-family: -apple-system, system-ui, sans-serif; font-size: 9px; color: #7a7a7a; width: 100%; padding: 0 20mm; display: flex; justify-content: space-between;">
          <span>PSPO·I Trainer — Analytics tracking plan</span>
          <span>Built ${builtAt}</span>
        </div>
      `,
      footerTemplate: `
        <div style="font-family: -apple-system, system-ui, sans-serif; font-size: 9px; color: #7a7a7a; width: 100%; padding: 0 20mm; display: flex; justify-content: space-between;">
          <span>commit ${sha}</span>
          <span class="pageNumber"></span> / <span class="totalPages"></span>
        </div>
      `,
    },
    stylesheet_encoding: 'utf-8',
    css: `
      body {
        font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Text', 'Inter', system-ui, sans-serif;
        font-size: 11px;
        line-height: 1.55;
        color: #1d1d1f;
        letter-spacing: -0.1px;
      }
      h1 {
        font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Display', 'Inter', system-ui, sans-serif;
        font-size: 26px;
        font-weight: 600;
        letter-spacing: -0.5px;
        margin: 28px 0 12px;
        padding-bottom: 8px;
        border-bottom: 2px solid #0066cc;
      }
      h2 {
        font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Display', 'Inter', system-ui, sans-serif;
        font-size: 18px;
        font-weight: 600;
        letter-spacing: -0.3px;
        margin: 28px 0 10px;
        color: #1d1d1f;
        padding-top: 6px;
      }
      h3 {
        font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Display', 'Inter', system-ui, sans-serif;
        font-size: 14px;
        font-weight: 600;
        letter-spacing: -0.2px;
        margin: 20px 0 8px;
        color: #0066cc;
      }
      h4 { font-size: 12px; font-weight: 600; margin: 16px 0 6px; }
      p, li { font-size: 11px; }
      ul, ol { padding-left: 22px; margin: 8px 0; }
      li { margin: 3px 0; }
      code {
        font-family: 'JetBrains Mono', ui-monospace, 'SF Mono', Menlo, monospace;
        background: #f5f5f7;
        padding: 1px 5px;
        border-radius: 4px;
        font-size: 10px;
        color: #1d1d1f;
      }
      pre {
        background: #f5f5f7;
        padding: 12px 14px;
        border-radius: 8px;
        overflow-x: auto;
        font-size: 10px;
        line-height: 1.5;
      }
      pre code {
        background: transparent;
        padding: 0;
        font-size: 10px;
      }
      table {
        width: 100%;
        border-collapse: collapse;
        margin: 12px 0;
        font-size: 10px;
        page-break-inside: avoid;
      }
      th, td {
        padding: 7px 10px;
        text-align: left;
        border-bottom: 1px solid #e0e0e0;
        vertical-align: top;
      }
      th {
        background: #f5f5f7;
        font-weight: 600;
        font-size: 10px;
        letter-spacing: -0.1px;
        border-bottom: 1px solid #d2d2d7;
      }
      blockquote {
        border-left: 3px solid #0066cc;
        padding: 10px 16px;
        background: #f5f5f7;
        margin: 14px 0;
        font-size: 10px;
        color: #1d1d1f;
        border-radius: 0 6px 6px 0;
      }
      blockquote p { margin: 4px 0; }
      hr {
        border: none;
        border-top: 1px solid #e0e0e0;
        margin: 24px 0;
      }
      a {
        color: #0066cc;
        text-decoration: none;
      }
      strong { font-weight: 600; }
      h2, h3, h4 { page-break-after: avoid; }
      pre, blockquote, table { page-break-inside: avoid; }
    `,
  },
);

console.log(`✓ ANALYTICS.pdf rebuilt (${sha} · ${builtAt})`);
